```tsx
import React, { useState, useEffect } from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { Menu, X } from 'lucide-react';
import { IMAGES } from '../constants';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close mobile menu when route changes
  useEffect(() => {
    setIsOpen(false);
  }, [location]);

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Services', path: '/services' },
    { name: 'Portfolio', path: '/portfolio' },
    { name: 'Contact', path: '/contact' },
  ];

  const baseLinkClasses = "font-medium transition-colors duration-200 hover:text-red-500";
  const activeLinkClasses = "text-red-500 font-semibold";
  const inactiveLinkClasses = "text-slate-600";

  return (
    <nav 
      className={`fixed w-full z-50 transition-all duration-300 ${
        scrolled ? 'bg-white shadow-md py-3' : 'bg-transparent py-5'
      }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          {/* Logo */}
          <NavLink to="/" className="flex items-center gap-2 group">
            <div className="w-10 h-10 rounded-full bg-red-500 flex items-center justify-center text-white overflow-hidden shadow-lg border-2 border-white">
                <img 
                  src={IMAGES.LOGO} 
                  alt="Amit Kumar" 
                  className="w-full h-full object-cover"
                />
            </div>
            <div className="flex flex-col">
                <span className={`text-xl font-bold leading-none ${scrolled ? 'text-slate-800' : 'text-slate-800 md:text-slate-900'}`}>
                    Amit Kumar
                </span>
                <span className="text-[10px] text-red-500 tracking-wider font-semibold">GROW WITH US</span>
            </div>
          </NavLink>

          {/* Desktop Menu */}
          <div className="hidden md:flex space-x-8">
            {navLinks.map((link) => (
              <NavLink
                key={link.name}
                to={link.path}
                className={({ isActive }) =>
                  `${baseLinkClasses} ${isActive ? activeLinkClasses : inactiveLinkClasses}`
                }
              >
                {link.name}
              </NavLink>
            ))}
            <a 
              href="https://wa.me/916205120223" 
              target="_blank" 
              rel="noreferrer"
              className="bg-red-500 hover:bg-red-600 text-white px-5 py-2 rounded-full font-medium transition-all transform hover:scale-105 shadow-md text-sm"
            >
              Let's Talk
            </a>
          </div>

          {/* Mobile Menu Button */}
          <button
            onClick={() => setIsOpen(!isOpen)}
            className="md:hidden text-slate-700 hover:text-red-500 focus:outline-none"
            aria-label="Toggle menu"
          >
            {isOpen ? <X size={28} /> : <Menu size={28} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu Dropdown */}
      <div 
        className={`md:hidden absolute top-full left-0 w-full bg-white shadow-lg transition-all duration-300 ease-in-out overflow-hidden ${
          isOpen ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'
        }`}
      >
        <div className="px-4 pt-2 pb-6 space-y-2 flex flex-col">
          {navLinks.map((link) => (
            <NavLink
              key={link.name}
              to={link.path}
              className={({ isActive }) =>
                `block px-3 py-3 rounded-md text-base ${
                  isActive ? 'text-red-500 bg-red-50 font-semibold' : 'text-slate-600 hover:text-red-500 hover:bg-slate-50'
                }`
              }
            >
              {link.name}
            </NavLink>
          ))}
          <a 
              href="https://wa.me/916205120223" 
              target="_blank" 
              rel="noreferrer"
              className="block text-center mt-4 bg-red-500 text-white py-3 rounded-lg font-medium"
            >
              Chat on WhatsApp
            </a>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

